<?php namespace App\Enums; enum AssetStatus:string{case Operational='operational';case Maintenance='maintenance';case Offline='offline';case Retired='retired'; public function label():string{return str($this->value)->headline();} public function color():string{return match($this){self::Operational=>'emerald',self::Maintenance=>'amber',self::Offline=>'rose',self::Retired=>'slate'};}}
